<template>
  <div>
   <span>平台提供（推荐）</span>
<table width="100%" border="0" cellpadding="0" cellspacing="0" bordercolor="#E8F6F7" bgcolor="#FFFFFF" class="BK">
  <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK2">
    	<span class="STYLE2">设备型号<br>(手机型号)</span>
    </td>
    <td class="BK3" width="60%" id="model"></td>
  </tr>
    <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK4">
    	<span class="STYLE2">手机系统</span>
    </td>
    <td class="BK3" id="platform"></td>
  </tr>
   <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK4">
    	<span class="STYLE2">手机系统版本</span>
    </td>
    <td class="BK3" id="version"></td>
  </tr>
  <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK4">
    	<span class="STYLE2">设备唯一ID</span>
    </td>
    <td class="BK3" id="deviceID"></td>
  </tr>
  <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK4">
    	<span class="STYLE2">设备MAC地址</span>
    </td>
    <td class="BK3" id="deviceMAC"></td>
  </tr>

  <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK4">
    	<span class="STYLE2">平台类型<br>(0门户 1一点通)</span>
    </td>
    <td class="BK3" id="portalType"></td>
  </tr>
  <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK4">
    	<span class="STYLE2">所属网络</span>
    </td>
    <td class="BK3" id="interStatus"></td>
  </tr>
</table>		



<table width="100%" border="0" cellspacing="0" cellpadding="0">
  <tr>









    <td width="25%">&nbsp;</td>
    <td width="45%">
    <table width="130" border="1" cellpadding="0" cellspacing="0" bordercolor="#FFFFFF" bgcolor="#0A7E81" @click="getInfo()">
      <tr>
        <td height="50" align="center"><span class="STYLE4">获取设备信息</span></td>
      </tr>
    </table>
    </td>
    <td width="30%">
	<table width="80" border="1" cellpadding="0" cellspacing="0" bordercolor="#FFFFFF" bgcolor="#0A7E81"
    	@click="clearData()">
      <tr>
        <td height="50" align="center"><span class="STYLE4">清除</span></td>
      </tr>
    </table>
	</td>

  

  </tr>
</table>
<br>





<!--*******************************-->







<span>Cordova 原生插件（不推荐）</span>

<table width="100%" border="0" cellpadding="0" cellspacing="0" bordercolor="#E8F6F7" bgcolor="#FFFFFF" class="BK">
  <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK2">
    	<span class="STYLE2">设备模型(手机名称)</span>
    </td>
    <td class="BK3" width="60%" id="deviceModel"></td>
  </tr>
  <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK4">
    	<span class="STYLE2">cordova版本</span>
    </td>
    <td class="BK3" id="deviceCordova"></td>
  </tr>

  <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK4">
    	<span class="STYLE2">手机uuid</span>
    </td>
    <td class="BK3" id="deviceUuid"></td>
  </tr>
    <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK4">
    	<span class="STYLE2">手机系统</span>
    </td>
    <td class="BK3" id="devicePlatform"></td>
  </tr>
   <tr>
    <td height="42" width="15%" align="center" bgcolor="#0A7E81" class="BK4">
    	<span class="STYLE2">手机系统版本</span>
    </td>
    <td class="BK3" id="deviceVersion"></td>
  </tr>
</table>		



<table width="100%" border="0" cellspacing="0" cellpadding="0">
  <tr>
    <td width="25%">&nbsp;</td>
    <td width="45%">
    <table width="130" border="1" cellpadding="0" cellspacing="0" bordercolor="#FFFFFF" bgcolor="#0A7E81" @click="getInfo2()">
      <tr>
        <td height="50" align="center"><span class="STYLE4">获取设备信息</span></td>
      </tr>
    </table>
    </td>
    <td width="30%"><table width="80" border="1" cellpadding="0" cellspacing="0" bordercolor="#FFFFFF" bgcolor="#0A7E81"
    	@click="clearData2()">
      <tr>
        <td height="50" align="center"><span class="STYLE4">清除</span></td>
      </tr>
    </table></td>
  </tr>
</table>
<br>



	<table width="80" border="1" cellpadding="0" cellspacing="0" bordercolor="#FFFFFF" bgcolor="#0A7E81"
    	@click="executeGoToScanPager()">
      <tr>
        <td height="50" align="center"><span class="STYLE4">指纹识别</span></td>
      </tr>
    </table><br><br>



	<p>
	<button @click="testupladFront();">前置上传测试</button>
	<button @click="testupladBack();">后置上传测试</button>
    </p>
    <p>
        <button @click="testCheckFront();">前置检测测试</button>
        <button @click="testCheckBack();">后置检测测试</button>
    </p>
    <p>
        <button @click="testErr1();">入参错误测试1</button>
        <button @click="testErr2();">入参错误测试2</button>
    </p><br><br>


<input type='button' @click="uploadFace()"  value='上传 uploadFace'></input>&nbsp;&nbsp;&nbsp;&nbsp;
<input type='button' @click="getFaceData()"  value='获取 getFaceData '></input>&nbsp;&nbsp;&nbsp;&nbsp;
<input type='button' @click="checkFace()"  value='对比 checkFace'></input><br><br><br><br>



<input type='button' @click="getHasMatchBts()"  value='获取蓝牙 getHasMatchBts'></input>&nbsp;&nbsp;&nbsp;&nbsp;<br><br>
<input type='button' @click="getNoMatchBts()"  value='获取蓝牙 getNoMatchBts'></input>&nbsp;&nbsp;&nbsp;&nbsp;<br><br>

<input type='texinput' size="25"  id='bluetoothid' placeholder='输入设备信息'></input><br><br>
<input type='button' @click="connectBluetooth()"  value='连接 connectBluetooth'></input>&nbsp;&nbsp;&nbsp;&nbsp;
<input type='button' @click="clearData2()"  value='清除'>
<br><br>

<textarea   rows="5" cols="40" id='getHasMatchBts' placeholder='getHasMatchBts'></textarea><br><br>
<textarea   rows="5" cols="40" id='getNoMatchBts' placeholder='getNoMatchBts'></textarea><br><br>
<textarea   rows="5" cols="40" id='connectBluetooth' placeholder='connectBluetooth'></textarea><br><br>
  </div>
</template>

<script>
export default {
  name: "deviceC", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      mam: { navigator: navigator },
    };
  },
  computed: {},
  created() {},
  mounted() {},
  activated() {},
  deactivated() {},
  watch: {},
  methods: {

	 getInfo(){
	console.log("调用获取设备信息插件 ");

	mam.navigator.devicemanage.getDevice(this.getInfoCallBack);
	},
	 getInfoCallBack(v){
	var json = JSON.stringify(v);
				alert("getJson插件调用成功: "+json);
		document.getElementById("model").innerHTML =v.model;//设备型号
		document.getElementById("platform").innerHTML = v.platform;//手机系统
		document.getElementById("version").innerHTML =v.version;//手机系统版本
		document.getElementById("deviceID").innerHTML =v.deviceID;//设备ID
		document.getElementById("interStatus").innerHTML =v.interStatus;//网络状态
		document.getElementById("portalType").innerHTML =v.portalType;//平台类型 0 门户 1一点通
		document.getElementById("deviceMAC").innerHTML =v.deviceMAC;//设备mac地址
		

	},
	 clearData(){
		document.getElementById("model").innerHTML = '';
		document.getElementById("platform").innerHTML = '';
		document.getElementById("version").innerHTML = '';
		document.getElementById("deviceID").innerHTML = '';
		document.getElementById("interStatus").innerHTML = '';
		document.getElementById("portalType").innerHTML = '';
	},

	 getInfo2(){
		console.log("testGetDevice()--->start()");
		if(!ready){
			return;
		}
		//device为window的内置对象
		var device = window.device;
		var devicejson = JSON.stringify(device);
		alert("getJson插件调用成功: "+devicejson);
		//获取设备类型
		var deviceModel = device.model;
		console.log("device.model:" + deviceModel);
		//获取cordova的版本号【在插件Device中直接定义的】
		var strCordova = device.cordova;
		console.log("device.cordova:" + strCordova);
		//设备平台【在插件Device中直接定义的】
		var devicePlatform = device.platform;
		console.log("device.platform:" + devicePlatform);
		//获取uuid:
		var strUuid = device.uuid;
		console.log(" device.uuid:" + strUuid);
		//设备版本号
		var version = device.version;
		console.log("device.version:" + version);
		console.log("testGetDevice()--->end()");
		//显示所有设备信息
		this.showDeivceInfo(device);
	},
	 showDeivceInfo(device){
		document.getElementById("deviceModel").innerHTML = device.model;
		document.getElementById("deviceCordova").innerHTML = device.cordova;
		document.getElementById("devicePlatform").innerHTML = device.platform;
		document.getElementById("deviceUuid").innerHTML = device.uuid;
		document.getElementById("deviceVersion").innerHTML = device.version;
	},
	 clearData2(){
		document.getElementById("deviceModel").innerHTML = '';
		document.getElementById("deviceCordova").innerHTML = '';
		document.getElementById("devicePlatform").innerHTML = '';
		document.getElementById("deviceUuid").innerHTML = '';
		document.getElementById("deviceVersion").innerHTML = '';

		document.getElementById("getHasMatchBts").value = '';
		document.getElementById("getNoMatchBts").value = '';
		document.getElementById("connectBluetooth").value = '';
		document.getElementById("bluetoothid").value = '';

	},


	/**
	*	方法：指纹识别
	*   功能：调用插件，用户按住 指纹识别设备，返回指纹状态信息
	**/
	 executeGoToScanPager(){

		alert("指纹识别开始；");

    	
    	mam.navigator.devicemanage.getFingerprint (successCallback,errcallback);
    	
    	//执行成功回调
    	//这边参数表示扫描成功后返回的字符串
    	function successCallback(v){
    	
			var v = JSON.stringify(v);
    	console.log("this.successCallback()  "+v);
			//alert("this.successCallback:"+v);
    		
    	}
    	
    	//执行失败回调[扫描失败，暂不退出界面未做处理]
    	function errcallback(e){
			var e = JSON.stringify(e);
			 console.log("errcallback()  "+e);

    		//alert("errcallback:"+e);
    	}
		 
    },
	

	 getHasMatchBts(){
		mam.navigator.bluetooth.getHasMatchBts (this.successCallback1,this.errcallback);
	},
	 getNoMatchBts(){
		mam.navigator.bluetooth.getNoMatchBts (this.successCallback2,this.errcallback);
	},
	 connectBluetooth(){
		var macAddress=document.getElementById("bluetoothid").value;
		alert(macAddress);
		mam.navigator.bluetooth.connectBluetooth (this.successCallback3,this.errcallback,macAddress);
	},
	 successCallback1(v){
		var v = JSON.stringify(v);
		document.getElementById('getHasMatchBts').value = v;
		console.log("this.successCallback()  "+v);			
	},
	 successCallback2(v){
		var v = JSON.stringify(v);
		document.getElementById('getNoMatchBts').value = v;
		console.log("this.successCallback()  "+v);			
	},
	 successCallback3(v){
		var v = JSON.stringify(v);
		document.getElementById('connectBluetooth').value = v;
		console.log("this.successCallback()  "+v);			
	},
	 errcallback(v){
		var v = JSON.stringify(v);
		document.getElementById('diyUrl').value = v;
		console.log("this.successCallback()  "+v);			
	},

//	0 上传成功(this.successCallback)
//	-1 采集数据异常(errorcallback)
//	-2 上传数据失败 (errorcallback)
 uploadFace (){
		mam.navigator.face.uploadFace("cs007", "js", false, this.faceSuccessCallback, this.faceErrorCallback);
	},

//	0 人脸识别成功(this.successCallback)
//	-3 不区配(errorcallback)
//	-5 调用接口失败未知错误 (errorcallback)
 checkFace (){
		mam.navigator.face.checkFace("cs007", "js", false, this.faceSuccessCallback, this.faceErrorCallback);
	},	
 getFaceData (){
		mam.navigator.face.getFaceData ("cs007","js",this.faceSuccessCallback);
},

 faceSuccessCallback (data){	
		  console.log("DATA----		"+ JSON.stringify(data) );	
},
 faceErrorCallback (data){	
		  console.log("DATA----		"+ JSON.stringify(data) );	
},


 testupladFront() {
            navigator.face.uploadFace("cs007", "js", false, this.successCallback, this.errorCallback);
        },

         testupladBack() {
            navigator.face.uploadFace("cs007", "js", true, this.successCallback, this.errorCallback);
        },

         testCheckFront() {
            navigator.face.checkFace("cs007", "js", false, this.successCallback, this.errorCallback);
        }

        , testCheckBack() {
            navigator.face.checkFace("cs007", "js", true, this.successCallback, this.errorCallback);
        }

        , testErr1() {
            navigator.face.uploadFace("11","22", true, this.successCallback, this.errorCallback);
        }

        , testErr2() {
            navigator.face.checkFace("11", "22", "33", "44", this.successCallback, this.errorCallback);
        }

        , successCallback(msg) {
            console.log('successCallback:' + JSON.stringify(msg));
        }

        , errorCallback(msg) {
            console.log('errorCallback:' + JSON.stringify(msg));
        }
  },
};
</script>
<style lang='css' scoped>
